import React, { useState, useCallback, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { validarEmail, validarPassword } from "../utils/validations";
import Button from "../components/Shared/Button";
import Input from "../components/Shared/Input";

/* ── Inline SVG icons (no extra dependency) ── */
const IconLogIn = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24"
    fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"
    aria-hidden="true">
    <path d="M15 3h4a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2h-4"/>
    <polyline points="10 17 15 12 10 7"/>
    <line x1="15" y1="12" x2="3" y2="12"/>
  </svg>
);

const IconZap = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24"
    fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"
    aria-hidden="true">
    <polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2"/>
  </svg>
);

const IconBarChart = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24"
    fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"
    aria-hidden="true">
    <line x1="18" y1="20" x2="18" y2="10"/>
    <line x1="12" y1="20" x2="12" y2="4"/>
    <line x1="6" y1="20" x2="6" y2="14"/>
  </svg>
);

const IconEye = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24"
    fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"
    aria-hidden="true">
    <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/>
    <circle cx="12" cy="12" r="3"/>
  </svg>
);

const IconShield = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24"
    fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"
    aria-hidden="true">
    <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/>
  </svg>
);

const FEATURES = [
  {
    Icon: IconZap,
    titulo: "Monitoreo en Tiempo Real",
    desc: "Visualiza el avance de cada obra instantáneamente con datos actualizados al momento.",
  },
  {
    Icon: IconBarChart,
    titulo: "Reportes Instantáneos",
    desc: "Genera análisis y estadísticas por programa con exportación a CSV y JSON.",
  },
  {
    Icon: IconEye,
    titulo: "Control de Períodos",
    desc: "Gestiona cortes semanales con apertura y cierre automático del sistema.",
  },
  {
    Icon: IconShield,
    titulo: "Auditoría Completa",
    desc: "Registro detallado de cada cambio: usuario, IP, delta y marca de tiempo.",
  },
];

/* ═══════════════════════════════════════════════════════════════
   Login — identidad visual gubernamental CDMX / SOBSE
   LÓGICA: 100% sin cambios. Solo refactor CSS/JSX.
═══════════════════════════════════════════════════════════════ */
export default function Login() {
  const navigate          = useNavigate();
  const { login, isAuthenticated } = useAuth();

  const [usuario, setUsuario]       = useState("");
  const [password, setPass]     = useState("");
  const [usuarioErr, setUsuarioErr] = useState("");
  const [passErr, setPassErr]   = useState("");
  const [apiErr, setApiErr]     = useState("");
  const [loading, setLoading]   = useState(false);
  const [touched, setTouched]   = useState({ usuario: false, pass: false });

  /* Si ya está autenticado, ir al dashboard */
  useEffect(() => {
    if (isAuthenticated) navigate("/dashboard", { replace: true });
  }, [isAuthenticated, navigate]);

  /* Validar en tiempo real solo si ya tocó el campo */
  useEffect(() => {
    if (touched.usuario) setUsuarioErr(validarEmail(usuario) || "");
  }, [usuario, touched.usuario]);

  useEffect(() => {
    if (touched.pass) setPassErr(validarPassword(password) || "");
  }, [password, touched.pass]);

  const canSubmit = !usuarioErr && !passErr && usuario && password;

  const handleSubmit = useCallback(async (e) => {
    e.preventDefault();
    setTouched({ email: true, pass: true });

    const eErr = validarEmail(email);
    const pErr = validarPassword(password);
    setEmailErr(eErr || "");
    setPassErr(pErr || "");
    if (eErr || pErr) return;

    setLoading(true);
    setApiErr("");

    const result = await login(email, password);
    setLoading(false);

    if (result.success) {
      navigate("/dashboard", { replace: true });
    } else {
      setApiErr(result.error);
    }
  }, [email, password, login, navigate]);

  /* ── RENDER ── */
  return (
    <div
      className="min-h-screen flex flex-col"
      style={{ backgroundColor: "#F5F3F0", fontFamily: '"Inter", -apple-system, sans-serif' }}
    >

      {/* ════════════════════════════════
          SECCIÓN 1 — HEADER GUBERNAMENTAL
          ════════════════════════════════ */}
      <header
        className="sticky top-0 z-40 bg-white"
        style={{ height: "80px", boxShadow: "0 2px 8px rgba(0,0,0,0.06)" }}
      >
        <div className="max-w-7xl mx-auto px-6 h-full flex items-center gap-3">
          <img
            src="https://plataformasobse.info/web/assets/img/LOGO-NUEVO.png"
            alt="Logotipo SOBSE — Secretaría de Obras y Servicios"
            className="object-contain"
            style={{ height: "56px", width: "auto" }}
          />
          <div
            className="self-stretch w-px mx-1"
            style={{ backgroundColor: "#D4C4B0" }}
          />
          <div>
            <p className="text-xs font-normal leading-tight" style={{ color: "#666666" }}>
              Gobierno de la Ciudad de México
            </p>
            <p className="font-semibold leading-tight" style={{ fontSize: "16px", color: "#691C32" }}>
              SOBSE
            </p>
          </div>
        </div>
      </header>

      {/* ════════════════════════════════
          SECCIÓN 2 — HERO
          ════════════════════════════════ */}
      <main className="flex-1 flex items-center justify-center px-4 sm:px-6 lg:px-8 py-12">
        <div className="w-full max-w-6xl">
          <div className="grid grid-cols-1 lg:grid-cols-5 gap-10 lg:gap-16 items-start">

            {/* ── Columna izquierda (3/5) ── */}
            <div className="lg:col-span-3 animate-fade-in">
              <h1
                className="font-bold mb-5"
                style={{
                  fontSize: "clamp(28px, 3.8vw, 48px)",
                  lineHeight: "1.2",
                  color: "#691C32",
                }}
              >
                Sistema Integral de Control
                <br className="hidden sm:block" />
                {" "}de Obra Pública SICOPS
              </h1>

              <p
                className="mb-8"
                style={{
                  fontSize: "16px",
                  color: "#666666",
                  lineHeight: "1.6",
                  maxWidth: "520px",
                }}
              >
                Sistema institucional para el control, seguimiento y supervisión en tiempo real
                de la obra pública en la Ciudad de México. Monitorea avances, toma decisiones
                informadas y asegura transparencia en cada proyecto.
              </p>

              {/* ── Formulario de acceso ── */}
              <div
                className="bg-white rounded-2xl p-8"
                style={{
                  boxShadow: "0 8px 24px rgba(0,0,0,0.08)",
                  border: "1px solid #D4C4B0",
                }}
              >
                <h2
                  className="font-semibold mb-6"
                  style={{ fontSize: "20px", color: "#2C2C2C" }}
                >
                  Centro de Captura
                </h2>

                <form onSubmit={handleSubmit} noValidate className="space-y-4">
                  <Input
                    label="Usuario o correo electrónico"
                    type="text"
                    id="login-email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    onBlur={() => setTouched((t) => ({ ...t, email: true }))}
                    error={emailErr}
                    placeholder="Usuario o correo electrónico"
                    required
                    autoComplete="username"
                    autoFocus
                  />

                  <Input
                    label="Contraseña"
                    type="password"
                    id="login-pass"
                    value={password}
                    onChange={(e) => setPass(e.target.value)}
                    onBlur={() => setTouched((t) => ({ ...t, pass: true }))}
                    error={passErr}
                    placeholder="••••••••"
                    required
                    autoComplete="current-password"
                  />

                  {/* Error API */}
                  {apiErr && (
                    <div
                      role="alert"
                      className="flex items-center gap-2 px-4 py-3 rounded-lg text-sm animate-shake"
                      style={{
                        backgroundColor: "#FEF2F2",
                        border: "1px solid #FECACA",
                        color: "#DC2626",
                      }}
                    >
                      <span aria-hidden="true">⚠️</span>
                      {apiErr}
                    </div>
                  )}

                  <Button
                    type="submit"
                    size="lg"
                    disabled={!canSubmit}
                    loading={loading}
                    className="w-full mt-2 gap-2 !bg-[#691C32] !border-[#691C32] hover:!bg-[#550A1F] hover:!border-[#550A1F] hover:scale-[1.01] transition-all duration-300"
                    style={{ boxShadow: "0 4px 12px rgba(105,28,50,0.2)" }}
                    aria-label="Acceder al Centro de Captura SICOPS"
                  >
                    <IconLogIn />
                    Acceder al Centro de Captura
                  </Button>
                </form>

                {/* Credenciales demo */}
                <div
                  className="mt-6 p-4 rounded-xl"
                  style={{
                    backgroundColor: "#F5F3F0",
                    border: "1px dashed #D4C4B0",
                  }}
                >
                  <p className="text-xs font-medium mb-1" style={{ color: "#666666" }}>
                    Credenciales de demostración:
                  </p>
                  <p className="text-xs font-mono" style={{ color: "#2C2C2C" }}>admin@obra.com</p>
                  <p className="text-xs font-mono" style={{ color: "#2C2C2C" }}>123456</p>
                </div>
              </div>
            </div>

            {/* ── Columna derecha (2/5) — Mascota ── */}
            <div className="lg:col-span-2 flex justify-center lg:pt-16 animate-slide-in">
              <div
                className="bg-white rounded-2xl p-8 text-center w-full"
                style={{
                  maxWidth: "300px",
                  boxShadow: "0 8px 24px rgba(0,0,0,0.12)",
                  border: "1px solid #D4C4B0",
                }}
              >
                <img
                  src="https://plataformasobse.info/web/assets/img/ajosobse.png"
                  alt="Mascota AJOSOBSE — asistente del sistema SICOPS"
                  className="mx-auto mb-5 object-contain transition-transform duration-300 ease-in-out hover:-translate-y-1"
                  style={{ width: "200px", height: "200px" }}
                />
                <p
                  className="font-medium"
                  style={{ fontSize: "14px", color: "#2C2C2C", lineHeight: "1.6" }}
                >
                  Bienvenido al sistema SICOPS.
                  <br />
                  Desde aquí podrás monitorear el avance
                  <br />
                  de las obras y tomar decisiones informadas.
                </p>
              </div>
            </div>

          </div>
        </div>
      </main>

      {/* ════════════════════════════════
          SECCIÓN 3 — CARACTERÍSTICAS
          ════════════════════════════════ */}
      <section className="px-4 sm:px-6 lg:px-8 pb-16">
        <div className="max-w-6xl mx-auto">
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5">
            {FEATURES.map(({ Icon, titulo, desc }) => (
              <div
                key={titulo}
                className="bg-white rounded-xl p-5 transition-all duration-300 ease-in-out hover:-translate-y-0.5 hover:shadow-md cursor-default"
                style={{
                  borderLeft: "4px solid #006341",
                  boxShadow: "0 4px 12px rgba(0,0,0,0.07)",
                  minHeight: "160px",
                }}
              >
                <div className="mb-3" style={{ color: "#006341" }}>
                  <Icon />
                </div>
                <h3
                  className="font-semibold mb-1"
                  style={{ fontSize: "14px", color: "#2C2C2C" }}
                >
                  {titulo}
                </h3>
                <p style={{ fontSize: "12px", color: "#666666", lineHeight: "1.5" }}>
                  {desc}
                </p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ════════════════════════════════
          SECCIÓN 4 — FOOTER
          ════════════════════════════════ */}
      <footer className="py-5 px-6" style={{ backgroundColor: "#691C32" }}>
        <div className="max-w-6xl mx-auto flex flex-col sm:flex-row items-center justify-between gap-2">
          <p className="text-sm" style={{ color: "rgba(255,255,255,0.8)" }}>
            © {new Date().getFullYear()} Gobierno de la Ciudad de México · SOBSE
          </p>
          <p className="text-xs font-medium" style={{ color: "#C9A66B" }}>
            SICOPS — Sistema Integral de Control de Obra Pública
          </p>
        </div>
      </footer>

    </div>
  );
}
